import sys
import heapq
from collections import defaultdict

def main():
    sys.setrecursionlimit(1 << 25)
    N, M = map(int, sys.stdin.readline().split())
    edges = []
    graph = defaultdict(list)
    for _ in range(M):
        u, v, w = map(int, sys.stdin.readline().split())
        graph[u].append((v, w))
        edges.append((u, v, w))

    # Step 1: Compute shortest paths from every node to every other node
    dist = [{} for _ in range(N + 1)]
    for u in range(1, N + 1):
        heap = [(0, u)]
        visited = set()
        while heap:
            d, v = heapq.heappop(heap)
            if v in visited:
                continue
            visited.add(v)
            dist[u][v] = d
            for nei, w in graph[v]:
                if nei not in visited:
                    heapq.heappush(heap, (d + w, nei))

    # Step 2: Try all permutations of nodes to find a path that covers all nodes
    from itertools import permutations
    min_total = float('inf')

    for perm in permutations(range(1, N + 1)):
        total = 0
        for i in range(len(perm) - 1):
            u = perm[i]
            v = perm[i + 1]
            if v not in dist[u]:
                break
            total += dist[u][v]
        else:
            if total < min_total:
                min_total = total

    if min_total != float('inf'):
        print(min_total)
    else:
        print("No")

if __name__ == "__main__":
    main()
